/* 4 · Concierge, live recommender (returns ONE real shop) */
const CQ=[
 {q:'What kind of evening is this?',opts:[
   {l:'A date',s:'Something considered',f:s=>s.r>=4.5&&s.t==='specialty'},
   {l:'With friends',s:'Easy and generous',f:s=>s.rc>=500},
   {l:'A study session',s:'Somewhere to sit a while',f:s=>latestClose(s)>=1290},
   {l:'A solo reset',s:'Quiet, for you',f:s=>s.r>=4.4}]},
 {q:'When are you going?',opts:[
   {l:'Right now',s:'Open this minute',f:s=>isOpenNow(s,NOW)},
   {l:'Later tonight',s:'Still open after ten',f:s=>latestClose(s)>=1320},
   {l:'Doesn’t matter',s:'Any time',f:s=>true}]},
 {q:'How far will you go?',opts:[
   {l:'Keep it close',s:'Near me',f:s=>true,near:true},
   {l:'Worth a drive',s:'Anywhere good in SoCal',f:s=>true}]}
];
let cStep=0, cAns=[];
function renderConcierge(){
  const box=$('#con');
  if(cStep>=CQ.length){renderConResult();return;}
  const Q=CQ[cStep];
  box.innerHTML=`<div class="con-prog">${CQ.map((_,i)=>`<span class="con-dot ${i<=cStep?'on':''}"></span>`).join('')}</div>
    <p class="con-q">${esc(Q.q)}</p><div class="con-opts">${Q.opts.map((o,i)=>`<button class="con-opt" data-i="${i}"><span><b>${esc(o.l)}</b><br><span>${esc(o.s)}</span></span></button>`).join('')}</div>
    ${cStep>0?'<button class="con-back" id="conBack">back</button>':''}`;
  $$('.con-opt',box).forEach(b=>b.addEventListener('click',()=>{cAns[cStep]=Q.opts[+b.dataset.i];cStep++;renderConcierge();}));
  const bk=$('#conBack');if(bk)bk.addEventListener('click',()=>{cStep--;renderConcierge();});
}
function renderConResult(){
  let list=SHOPS.slice();
  cAns.forEach(a=>{if(a&&a.f)list=list.filter(a.f);});
  const wantNear=cAns.some(a=>a&&a.near);
  if(!list.length)list=SHOPS.slice();
  if(wantNear&&userLoc)list.sort((a,b)=>distOf(a)-distOf(b));
  else if(userLoc)list.sort((a,b)=>distOf(a)-distOf(b)||weight(b)-weight(a));
  else list.sort((a,b)=>weight(b)-weight(a));
  const pick=list[0];const open=isOpenNow(pick,NOW);
  $('#con').innerHTML=`<div class="con-result">
    <p class="rk">Your room tonight</p>
    <p class="rn">${esc(pick.n)}</p>
    <p class="rc2">${esc(pick.c)}${wantNear&&userLoc?` · ${distOf(pick).toFixed(1)} mi from you`:''}</p>
    <div class="rmeta">${pick.r?`<span class="stars">${stars(pick.r)}</span> <span class="rc">${pick.rc.toLocaleString()} reviews</span>`:''}
      ${pick.pl?`<span class="dollar">${dollars(pick.pl)}</span>`:''}
      ${open?'<span class="pill open">● Open now</span>':'<span class="pill shut">Closed now</span>'}</div>
    <div class="btns"><a class="btn" href="${profileURL(pick)}" target="_blank" rel="noopener">Open the shop</a>
      <button class="btn ghost" id="conAgain">Start over</button>
      <button class="btn ghost" id="conNext">Another match</button></div></div>`;
  $('#conAgain').addEventListener('click',()=>{cStep=0;cAns=[];renderConcierge();});
  let ptr=0;$('#conNext').addEventListener('click',()=>{ptr=(ptr+1)%Math.min(list.length,8);const p2=list[ptr];const o2=isOpenNow(p2,NOW);
    $('.con-result .rn').textContent=p2.n;$('.con-result .rc2').textContent=p2.c+(wantNear&&userLoc?` · ${distOf(p2).toFixed(1)} mi from you`:'');
    $('.con-result .btn').href=profileURL(p2);
    $('.con-result .rmeta').innerHTML=`${p2.r?`<span class="stars">${stars(p2.r)}</span> <span class="rc">${p2.rc.toLocaleString()} reviews</span>`:''} ${p2.pl?`<span class="dollar">${dollars(p2.pl)}</span>`:''} ${o2?'<span class="pill open">● Open now</span>':'<span class="pill shut">Closed now</span>'}`;});
}

