/* 9 · Society Directory, live counts from the loaded dataset */
function numWords(n){
  const ones=['zero','one','two','three','four','five','six','seven','eight','nine','ten','eleven','twelve','thirteen','fourteen','fifteen','sixteen','seventeen','eighteen','nineteen'];
  const tens=['','','twenty','thirty','forty','fifty','sixty','seventy','eighty','ninety'];
  if(n<20)return ones[n];
  if(n<100)return tens[Math.floor(n/10)]+(n%10?'-'+ones[n%10]:'');
  if(n<1000){const r=n%100;return ones[Math.floor(n/100)]+' hundred'+(r?' and '+numWords(r):'');}
  return String(n);
}
function renderDir(){
  const byReg={},byCity={};
  SHOPS.forEach(s=>{const r=regionOf(s);byReg[r]=(byReg[r]||0)+1;(byCity[s.cs]=byCity[s.cs]||{c:s.c,cs:s.cs,n:0}).n++;});
  const total=SHOPS.length, cities=Object.keys(byCity).length, regs=Object.keys(byReg).length;
  const h=$('#dirH2');if(h)h.textContent='Find boba shops near you.';
  const l=$('#dirLede');if(l)l.textContent=`${total} boba shops across ${cities} Southern California cities, hours checked against official sources. Search by city, shop, or drink, filter chains or independents, and keep a list.`;
  const ar=$('#dirAreas');if(ar){ar.innerHTML='';
    Object.keys(REGIONS).filter(k=>byReg[k]).sort((a,b)=>byReg[b]-byReg[a]).forEach(k=>{const R=REGIONS[k];
      const a=document.createElement('a');a.className='dirx-area';a.href=BASE+R.path;a.target='_blank';a.rel='noopener';
      a.innerHTML=`<span class="da-n">${byReg[k]}</span><span class="da-t">${esc(R.name)}</span><span class="da-s">${esc(R.sub)}</span>`;ar.appendChild(a);});
    const all=document.createElement('a');all.className='dirx-area';all.href=BASE+'/directory/';all.target='_blank';all.rel='noopener';
    all.innerHTML=`<span class="da-n">${total}</span><span class="da-t">All regions</span><span class="da-s">The full directory</span>`;ar.appendChild(all);}
  const cc=$('#cityChips');if(cc){cc.innerHTML='';
    Object.values(byCity).sort((a,b)=>b.n-a.n).slice(0,16).forEach(c=>{const a=document.createElement('a');
      a.href=`${BASE}/boba/ca/${c.cs}/`;a.target='_blank';a.rel='noopener';a.className='citychip';a.textContent=c.c;cc.appendChild(a);});}
}

/* 8 · roll the night */
function wireSpin(){
  const btn=$('#spinBtn'); if(!btn||btn._w)return; btn._w=1;
  btn.addEventListener('click',()=>{
    const pool=SHOPS.filter(s=>isOpenNow(s,NOW)); const src=pool.length?pool:SHOPS; if(!src.length)return;
    const sp=$('#spinner'); let t=0;
    const iv=setInterval(()=>{sp.style.transform=`rotate(${(t+=48)}deg)`; const r=src[Math.floor(Math.random()*src.length)]; $('#spinName').textContent=r.n;},60);
    setTimeout(()=>{clearInterval(iv); sp.style.transform='rotate(0deg)';
      const pick= (userLoc? src.slice().sort((a,b)=>distOf(a)-distOf(b)).slice(0,Math.min(12,src.length)) : src)[Math.floor(Math.random()*Math.min(userLoc?12:src.length,src.length))];
      $('#spinName').innerHTML=`<a href="${profileURL(pick)}" target="_blank" rel="noopener" style="color:var(--gilt);font-weight:600">${esc(pick.n)}</a>`;
      $('#spinCity').textContent=`${pick.c}${userLoc?` · ${distOf(pick).toFixed(1)} mi`:''} · ${stars(pick.r)} (${pick.rc.toLocaleString()}) ${isOpenNow(pick,NOW)?'· open now':''}`;
      $('#spinGo').href=profileURL(pick);
    },900);
  });
}

