function galGo(i){
  galIdx=((i%2)+2)%2;
  const t=$('#galTrack');if(!t)return;
  t.style.transform='translateX(-'+(galIdx*100)+'%)';
  const head=$('#galHead'),g=GAL[galIdx];
  if(head){head.classList.add('swapping');
    setTimeout(()=>{$('#galKick').textContent=g.k;$('#galH2').textContent=g.h;$('#galLede').textContent=g.l;head.classList.remove('swapping');},220);}
  const pl=$('#galPlaque');if(pl)pl.textContent=g.p;
}
(function wireGallery(){
  const pv=$('#galPrev'),nx=$('#galNext');
  if(pv)pv.addEventListener('click',()=>galGo(galIdx-1));
  if(nx)nx.addEventListener('click',()=>galGo(galIdx+1));
})();

const BELT_SPEEDS=[48,40];

function beltify(trackId,speed){
  const track=document.getElementById(trackId);if(!track)return;
  const group=track.querySelector('.belt-group:not([aria-hidden])');if(!group||!group.children.length)return;
  track.querySelectorAll('.belt-group[aria-hidden]').forEach(n=>n.remove());
  const clone=group.cloneNode(true);clone.setAttribute('aria-hidden','true');
  clone.querySelectorAll('[id]').forEach(n=>n.removeAttribute('id'));clone.removeAttribute('id');
  track.appendChild(clone);
  const w=group.getBoundingClientRect().width;
  track.style.setProperty('--dur',Math.max(28,Math.round(w/(speed||40)))+'s');
}
function beltifyAll(){beltify('trendTrack',BELT_SPEEDS[0]);beltify('worthTrack',BELT_SPEEDS[1]);}
(function wireChainTog(){
  const btns=[].slice.call(document.querySelectorAll('.belt-tog[data-tog="chains"]'));if(!btns.length)return;
  function paint(){btns.forEach(b=>{
    b.setAttribute('aria-pressed',String(chainsIn));
    const t=b.querySelector('.ctTxt'),u=b.querySelector('.ctSub');
    if(t)t.textContent=chainsIn?'Chains included':'Independents only';
    if(u)u.textContent=chainsIn?'tap for independents only':'tap to include chains';
    b.title=chainsIn?'Chains are included. Tap for independents only.':'Showing independent shops only. Tap to include chains.';});}
  btns.forEach(b=>b.addEventListener('click',()=>{
    chainsIn=!chainsIn;paint();
    renderOpenNear();renderTrending();renderWorth();renderAfterTen();beltifyAll();
  }));
  paint();
})();

function renderAll(){NOW=pacificNow();
  renderOpenNear();renderTrending();renderCAD();if(cStep===0)renderConcierge();renderWorth();renderHouse();renderDrinks();renderAfterTen();renderDir();renderKeep();wireSpin();ensureFinder();beltifyAll();}

